import { Injectable, Logger } from '@nestjs/common';

import { AlgoliaService } from '@modules/algolia/algolia.service';
import { CondensedFeaturesService } from '@modules/db/condensed-features/condensed-features.service';
import { ICondensedFeaturesBase } from '@modules/db/condensed-features/types/condensed-features.base.interface';
import { ProductAnnualSalesService } from '@modules/db/product-annual-sales/product-annual-sales.service';
import { StylesService } from '@modules/db/styles/styles.service';
import { StylesHashService } from '@modules/db/styles-hash/styles-hash.service';
import { IStylesHashBase } from '@modules/db/styles-hash/types/styles-hash.base.interface';
import { MmsService } from '@modules/mms/mms.service';
import { OpenAIService } from '@modules/rest/open-ai/open-ai.service';

import { convertRGBToString } from '@utils/color-match.util';
import { compareHashes } from '@utils/compare-hashes.util';
import { getEnv } from '@utils/get-env-variable.util';
import { hashFromObject } from '@utils/hash-from-object.unit';
import { withRetry } from '@utils/retry.util';

import {
	ALGOLIA_OBJECT_ID_SUFFIXES,
	DEFAULT_PRICING_ALGORITHM,
	EXCLUDED_CAT_NAMES,
	STYLES_HASHING_ALGORITHM,
	styleStatus,
	TAXONOMY_CAT_IDS,
} from '@constants/common.constant';
import { MMS_IMAGES_LAMBDA_HOST } from '@constants/env-variables.constant';

import {
	Breadcrumb,
	FeaturesRelatedFields,
	MMSAllStyleCategory,
	MMSResponse,
	MMSStyleToProcess,
} from '@interfaces/mms-style-to-process.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

@Injectable()
export class ProcessStyleService {
	private readonly logger = new Logger(ProcessStyleService.name);
	private readonly mmsImagesLambdaHost = getEnv({ key: MMS_IMAGES_LAMBDA_HOST });

	constructor(
		private readonly stylesHashService: StylesHashService,
		private readonly condensedFeaturesService: CondensedFeaturesService,
		private readonly OpenAIService: OpenAIService,
		private readonly algoliaService: AlgoliaService,
		private readonly mmsService: MmsService,
		private readonly productAnnualSalesService: ProductAnnualSalesService,
		private readonly stylesService: StylesService,
	) {}

	@LogExecution({
		paramFormatter: (params) => params,
		responseFormatter: (response) => response,
		logErrToRollbar: false,
		logParams: false,
		logResponse: false,
		logLongExecution: false,
	})
	public async process({
		style,
		allCategories,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
	}): Promise<boolean> {
		try {
			if (!this.isProductAllowedToProcess(style)) {
				this.logger.debug(`Style ${style.id} is not allowed to process.`);
				await Promise.all([
					this.deleteFromAlgoliaIndex({ styleId: style.id }),
					this.deleteCondensedFeatures({ styleId: style.id }),
				]);
				return false;
			}

			if (!style.colors?.length) {
				this.logger.debug(`Style ${style.id} has no colors, skipping processing.`);
				await Promise.all([
					this.deleteFromAlgoliaIndex({ styleId: style.id }),
					this.deleteCondensedFeatures({ styleId: style.id }),
				]);
				return false;
			}

			const featuresRelatedFields = this.extractFeaturesRelatedFields({
				style,
				allCategories,
			});

			const isProductActive = this.checkIsProductActive({
				status: style.status,
				colors: style.colors,
			});

			await this.saveStyleToDatabase({ style, allCategories, isProductActive });

			const newHash = hashFromObject({
				obj: featuresRelatedFields as unknown as Record<string, unknown>,
			});
			const storedHash = await this.getStoredHash({ styleId: style.id });

			const isCondensedFeaturesExists =
				await this.condensedFeaturesService.getCondensedFeature({
					styleId: style.id,
				});

			if (!storedHash) {
				if (!isCondensedFeaturesExists) {
					this.logger.debug(
						`Style ${style.id}: no hash, no features. Creating new features`,
					);

					const condensedFeatures = isProductActive
						? await this.generateLLMFeatures({ style, featuresRelatedFields })
						: [];
					await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
					await this.createHash({ styleId: style.id, hash: newHash });
					await this.updateAlgoliaIndex({
						style,
						allCategories,
						condensedFeatures,
					});
				} else {
					this.logger.debug(
						`Style ${style.id}: no hash, but features exist. Generating hash`,
					);
					await this.createHash({ styleId: style.id, hash: newHash });
					await this.updateAlgoliaIndex({
						style,
						allCategories,
						condensedFeatures: isCondensedFeaturesExists.condensed_features,
					});
				}

				return true;
			} else if (storedHash && !compareHashes({ hash1: newHash, hash2: storedHash })) {
				this.logger.debug(`Style ${style.id}: hash changed, updating features and index`);

				const condensedFeatures = isProductActive
					? await this.generateLLMFeatures({ style, featuresRelatedFields })
					: (isCondensedFeaturesExists?.condensed_features ?? []);
				await this.updateStoredHash({ styleId: style.id, hash: newHash });
				await this.updateCondensedFeatures({ styleId: style.id, condensedFeatures });
				await this.updateAlgoliaIndex({
					style,
					allCategories,
					condensedFeatures,
				});
				return true;
			} else if (storedHash && !isCondensedFeaturesExists) {
				this.logger.debug(
					`Style ${style.id}: hash exists, but no features exist. Creating new features`,
				);
				const condensedFeatures = isProductActive
					? await this.generateLLMFeatures({ style, featuresRelatedFields })
					: [];
				await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
				await this.updateAlgoliaIndex({
					style,
					allCategories,
					condensedFeatures,
				});
				return true;
			}

			await this.updateAlgoliaIndex({
				style,
				allCategories,
				condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
			});
			this.logger.debug(`Style ${style.id}: hash is the same, no changes needed`);
			return false;
		} catch (error) {
			this.logger.error(`Error processing style ${style.id}:`, error);
			throw error;
		}
	}

	public async fetchStylesFromMMS({
		page,
		perPage,
		timeoutMs,
	}: {
		page: number;
		perPage?: number;
		timeoutMs?: number;
	}): Promise<MMSResponse> {
		return this.mmsService.fetchStyles({
			page,
			...(perPage !== undefined && { perPage }),
			...(timeoutMs !== undefined && { timeoutMs }),
		});
	}

	private checkIsProductActive({
		status,
		colors,
	}: {
		status: string;
		colors: MMSStyleToProcess['colors'];
	}): boolean {
		if (status === styleStatus.ACTIVE) {
			if (colors?.length) {
				return colors.some((color) => color.status === styleStatus.ACTIVE);
			}

			return true;
		}

		return false;
	}

	private isProductAllowedToProcess(style: MMSStyleToProcess): boolean {
		const name = String(style.name);
		const formattedName = name.toLowerCase();
		const isCanadian =
			formattedName.includes('canada') || formattedName.includes('canadian');

		return !isCanadian;
	}

	private async getStoredHash({
		styleId,
	}: {
		styleId: number;
	}): Promise<IStylesHashBase['hash'] | null> {
		const hashRecord = await this.stylesHashService.getStyleHash({ styleId });

		if (!hashRecord) {
			this.logger.debug(`No stored hash found for style ${styleId}`);
			return null;
		}

		return hashRecord.hash;
	}

	private async createHash({
		styleId,
		hash,
	}: {
		styleId: number;
		hash: string;
	}): Promise<void> {
		await this.stylesHashService.createStyleHash({
			data: {
				style_id: styleId,
				hash,
				hashing_algorithm: STYLES_HASHING_ALGORITHM,
			},
		});
		this.logger.debug(`Created new hash for style ${styleId}: ${hash}`);
	}

	private async updateStoredHash({
		styleId,
		hash,
	}: {
		styleId: number;
		hash: string;
	}): Promise<void> {
		await this.stylesHashService.updateHashValue({
			styleId,
			hash,
			algorithm: STYLES_HASHING_ALGORITHM,
		});
		this.logger.debug(`Updated hash for style ${styleId} to ${hash}`);
	}

	private async saveStyleToDatabase({
		style,
		allCategories,
		isProductActive,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
		isProductActive: boolean;
	}): Promise<void> {
		try {
			const categoryIds = this.extractCategoryIds({ style });
			const categoriesWithParentsIds = this.extractCategoriesWithParents({
				categoryIds,
				allCategories,
			});

			const purchasesCount =
				await this.productAnnualSalesService.getPurchasesCountForLatestYear({
					styleId: Number(style.id),
				});

			const styleData = {
				style_id: style.id,
				primary_category_id: style.primary_category_id ?? 0,
				root_category_id: this.getRootCategoryId({ style, allCategories }),
				purchases_count: purchasesCount,
				is_active: isProductActive,
				name: style.name,
				decoration_method: style.decoration_method,
				features: style.features,
				general_comments: style.general_comments,
				manufacturer: style.manufacturer,
				minimum_quantity: style.min_qty,
				rating_count: style.rating_count,
				rating_score: Number(style.rating_score),
				sizes: (style.style_sizes ?? []).map((size) => size.name),
				style_type: style.style_type,
				price_level: style.price_level,
				primary_category_name: style.primary_category?.name ?? '',
				default_quote_qty: style.primary_category?.default_quote_qty ?? 1,
				product_type: style.product_type,
				style_card_image_url: this.generateStyleCardImageUrl({
					styleId: style.id,
					catalogDetailImageMd5: style.catalog_detail_image_md5,
				}),
				broad_category_names: this.getBroadCategoryNames({
					categories: style.categories,
					allCategories,
				}),
				sub_category_names: this.getStylesSubcategories({
					categories: style.categories,
					allCategories,
				}),
				turn_time: style.turntime ? Number(style.turntime.standard) : 0,
				rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
				no_minimum: style.has_singles_enabled_colors,
				link_path: this.calculateLink({ style, allCategories })?.path ?? '',
				brand: this.getBrand([style.brand]),
				min_qty: style.min_qty,
			};

			if (!style.colors?.length) {
				this.logger.debug(`Style ${style.id} has no colors to save`);
				return;
			}

			const colors = style.colors.map((color) => {
				const isActive = color.status === styleStatus.ACTIVE;
				const hasRgb = Array.isArray(color.rbgs) && color.rbgs[0];
				const colorRgb =
					hasRgb && color.rbgs[0] ? convertRGBToString({ rgb: color.rbgs[0] }) : null;

				return {
					color_id: color.id,
					color_rgb: colorRgb,
					color_name: color.name,
					is_active: Boolean(isActive && hasRgb),
					image_url: color.image_url,
				};
			});

			const defaultUnitPrices = this.getDefaultUnitPrices({ style }).map((priceData) => ({
				quantity: priceData.quantity,
				price: Number(priceData.price),
				regular_unit_price: priceData.regular_unit_price
					? Number(priceData.regular_unit_price)
					: null,
				algorithm: priceData.algorithm,
			}));

			await this.stylesService.saveCompleteStyle({
				styleData,
				colors,
				defaultUnitPrices,
				categoryIds,
				categoriesWithParentsIds,
			});

			this.logger.debug(`Successfully saved style ${style.id} to database`);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to save style ${style.id} to database: ${err.message}`);
			throw err;
		}
	}

	private async generateLLMFeatures({
		style,
		featuresRelatedFields,
	}: {
		style: MMSStyleToProcess;
		featuresRelatedFields: FeaturesRelatedFields;
	}): Promise<string[]> {
		try {
			const result = await withRetry({
				fn: () => this.OpenAIService.generateProductFeatures({ productInfo: style }),
				options: { retryCount: 2 },
			});

			if (result.error) {
				this.logger.error(
					`Failed to generate features for style ${style.id}: ${result.error}`,
				);
				throw new Error(`Failed to generate features: ${result.error}`);
			}

			return result.description ?? [];
		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			const isTokenLimitError = errorMessage.includes('maximum context length');

			if (isTokenLimitError) {
				this.logger.warn(
					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
				);

				const reducedResult = await withRetry({
					fn: () =>
						this.OpenAIService.generateProductFeatures({
							productInfo: featuresRelatedFields as unknown as MMSStyleToProcess,
						}),
					options: { retryCount: 2 },
				});

				if (reducedResult.error) {
					throw new Error(`Failed to generate features: ${reducedResult.error}`);
				}

				this.logger.debug(
					`Successfully generated features for style ${style.id} using reduced fields`,
				);
				return reducedResult.description ?? [];
			}

			this.logger.error(`Failed to generate features for style ${style.id}:`, error);
			throw error;
		}
	}

	private async saveCondensedFeatures({
		styleId,
		condensedFeatures,
	}: {
		styleId: number;
		condensedFeatures: string[];
	}): Promise<void> {
		await this.condensedFeaturesService.upsertCondensedFeature({
			data: { style_id: styleId, condensed_features: condensedFeatures },
		});

		this.logger.debug(
			`Condensed features saved for style ${styleId}: ${condensedFeatures.join(', ')}`,
		);
	}

	private async updateCondensedFeatures({
		styleId,
		condensedFeatures,
	}: {
		styleId: ICondensedFeaturesBase['style_id'];
		condensedFeatures: string[];
	}): Promise<void> {
		await this.condensedFeaturesService.updateCondensedFeature({
			styleId,
			condensedFeatures,
		});

		this.logger.debug(
			`Condensed features saved for style ${styleId}: ${condensedFeatures.join(', ')}`,
		);
	}

	private async deleteCondensedFeatures({
		styleId,
	}: {
		styleId: ICondensedFeaturesBase['style_id'];
	}): Promise<void> {
		await this.condensedFeaturesService.deleteCondensedFeature({ styleId });
		this.logger.debug(`Deleted condensed features for style ${styleId}`);
	}

	private async updateAlgoliaIndex({
		style,
		allCategories,
		condensedFeatures,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
		condensedFeatures?: string[];
	}): Promise<void> {
		const algoliaStyle = {
			objectID: String(style.id),
			name: style.name,
			primary_category_id: style.primary_category_id,
			brand: this.getBrand([style.brand]),
			condensed_features: condensedFeatures ?? [],
			sub_category_names: this.getStylesSubcategories({
				categories: style.categories,
				allCategories,
			}),
			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
			price_level: style.price_level,
			product_id: style.id,
			product_type: style.product_type,
			style_card_image_url: this.generateStyleCardImageUrl({
				styleId: style.id,
				catalogDetailImageMd5: style.catalog_detail_image_md5,
			}),
		};

		// eslint-disable-next-line no-console
		console.log('!!!!!!!!!!!!!!!!!!!!!!!!!', style['objectID']);

		const objects = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => ({
			...algoliaStyle,
			objectID: `${style['objectID']}-${suffix}`,
			index_suffix: suffix,
		}));

		await this.algoliaService.saveObjects({ objects });
	}

	private async deleteFromAlgoliaIndex({ styleId }: { styleId: number }): Promise<void> {
		const objectIds = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => `${styleId}-${suffix}`);
		await this.algoliaService.deleteObjects({ objectIds });
		this.logger.debug(`Deleted style ${styleId} from Algolia index (all suffixes)`);
	}

	private extractFeaturesRelatedFields({
		style,
		allCategories,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
	}): FeaturesRelatedFields {
		return {
			name: style.name,
			decoration_method: style.decoration_method,
			features: style.features,
			general_comments: style.general_comments,
			manufacturer: style.manufacturer,
			sizes: (style.style_sizes ?? []).map((size) => size.name),
			style_type: style.style_type,
			price_level: style.price_level,
			primary_category_name: style.primary_category?.name ?? '',
			product_type: style.product_type,
			broad_category_names: this.getBroadCategoryNames({
				categories: style.categories,
				allCategories,
			}),
			sub_category_names: this.getStylesSubcategories({
				categories: style.categories,
				allCategories,
			}),
			turn_time: style.turntime ? Number(style.turntime.standard) : 0,
			rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
		};
	}

	private getDefaultUnitPrices({
		style,
	}: {
		style: MMSStyleToProcess;
	}): MMSStyleToProcess['default_unit_prices'] {
		return style.default_unit_prices.reduce<MMSStyleToProcess['default_unit_prices']>(
			(acc, pricesObj) => {
				if (pricesObj.algorithm !== DEFAULT_PRICING_ALGORITHM) {
					return acc;
				}

				acc.push({
					quantity: pricesObj.quantity,
					price: pricesObj.price,
					algorithm: pricesObj.algorithm,
					regular_unit_price: pricesObj.regular_unit_price ?? null,
				});

				return acc;
			},
			[],
		);
	}

	private generateStyleCardImageUrl({
		styleId,
		catalogDetailImageMd5,
	}: {
		styleId: number;
		catalogDetailImageMd5: string | null;
	}): string {
		const basePath = '/mms/images/catalog/';
		const md5Path = catalogDetailImageMd5 ? `${catalogDetailImageMd5}/` : '';
		const stylePath = `styles/${styleId}/catalog_detail_image_medium.jpg`;

		return `${this.mmsImagesLambdaHost}${basePath}${md5Path}${stylePath}`;
	}

	private getBroadCategoryNames({
		categories,
		allCategories,
	}: {
		styleId?: number;
		categories: MMSStyleToProcess['categories'];
		allCategories: MMSAllStyleCategory[];
	}): string[] {
		const activeCategories = categories
			.map((cat) => {
				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
				if (fullCategory) {
					cat['parent'] = fullCategory;
				}
				return cat;
			})
			.filter((cat) => cat.active);

		const allParents = activeCategories
			.map((category) => category['parent'] ?? { ...category, _id: category.id })
			.filter(Boolean) as MMSAllStyleCategory[];

		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
				return acc;
			}

			if (!acc.some((p) => p._id === parent._id)) {
				acc.push(parent);
			}

			return acc;
		}, []);

		const names = uniqueParents
			.map((parent) => parent['name'])
			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];

		return [...new Set(names)];
	}

	private getStylesSubcategories({
		categories,
		allCategories,
	}: {
		categories: MMSStyleToProcess['categories'];
		allCategories: MMSAllStyleCategory[];
	}): string[] {
		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);

		const childCategories: string[] = [];

		for (const category of activeCategories) {
			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);

			if (!hasChildren && category.name) {
				childCategories.push(category.name);
			}
		}

		return [...new Set(childCategories)];
	}

	private getBrand<T>(array: (T | null | undefined)[]): T[] {
		return array.filter(Boolean) as T[];
	}

	private calculateLink({
		style,
		allCategories,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
	}): Breadcrumb | null {
		function urlFriendly(str: string): string {
			return str
				.toLowerCase()
				.replace(/&reg;/g, '®')
				.replace(/\//g, '-')
				.replace(/\s+/g, '-')
				.replace(/[^\+\-0-9_a-z]/g, '')
				.replace(/^-+|-+$/g, '')
				.replace(/-+/g, '-');
		}

		const primaryCategory = style.primary_category;

		if (!primaryCategory) {
			return null;
		}

		const primaryCatParent = allCategories.find(
			(cat) => cat._id === primaryCategory.parent_id,
		);

		const primaryCatParentName = primaryCatParent?.['name'] as string;
		const categoryName = primaryCategory.name;

		const firstPartLink = !primaryCatParent
			? '/products'
			: `/products/${urlFriendly(primaryCatParentName)}`;

		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;

		return {
			name: style.name,
			path: path,
		};
	}

	private extractCategoryIds({ style }: { style: MMSStyleToProcess }): number[] {
		const activeCategories = style.categories.filter((cat) => cat.active);
		return activeCategories.map((cat) => cat.id);
	}

	private extractCategoriesWithParents({
		categoryIds,
		allCategories,
	}: {
		categoryIds: number[];
		allCategories: MMSAllStyleCategory[];
	}): number[] {
		const allCategoryIds = new Set<number>();

		for (const categoryId of categoryIds) {
			allCategoryIds.add(categoryId);

			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
			for (const parentId of parentIds) {
				allCategoryIds.add(parentId);
			}
		}

		return Array.from(allCategoryIds).sort((a, b) => a - b);
	}

	private getAllParentCategoryIds({
		categoryId,
		allCategories,
	}: {
		categoryId: number;
		allCategories: MMSAllStyleCategory[];
	}): number[] {
		const parents: number[] = [];
		const category = allCategories.find((cat) => cat._id === categoryId);

		if (!category?.['parent_id']) {
			return parents;
		}

		let currentParentId = category['parent_id'] as number;

		while (currentParentId) {
			parents.push(currentParentId);

			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
			if (!parentCategory?.['parent_id']) {
				break;
			}

			currentParentId = parentCategory['parent_id'] as number;
		}

		return parents;
	}

	private getRootCategoryId({
		style,
		allCategories,
	}: {
		style: MMSStyleToProcess;
		allCategories: MMSAllStyleCategory[];
	}): number | null {
		if (!style.primary_category) {
			return null;
		}

		const primaryCategory = allCategories.find(
			(cat) => cat._id === style.primary_category_id,
		);
		if (!primaryCategory) {
			return null;
		}

		let currentCategory = primaryCategory;
		while (currentCategory['parent_id']) {
			const parentCategory = allCategories.find(
				(cat) => cat._id === currentCategory['parent_id'],
			);
			if (!parentCategory) break;
			currentCategory = parentCategory;
		}

		return !currentCategory['parent_id'] ? currentCategory._id : null;
	}
}

