import { Logger } from '@nestjs/common';
import { Command, CommandRunner } from 'nest-commander';

import { StyleAlternativesService } from '@modules/db/style-alternatives/style-alternatives.service';
import { MmsService } from '@modules/mms/mms.service';
import { ProcessStyleService } from '@modules/rest/process-style/process-style.service';

import { runWithConcurrencyLimit } from '@utils/concurrency-pool.util';
import { ProgressBar } from '@utils/progress-bar.util';

import {
	MMSAllStyleCategory,
	MMSStyleToProcess,
} from '@interfaces/mms-style-to-process.interface';

import { CronJobExecution } from '@decorators/cron-job-execution.decorator';

@Command({
	name: 'sync-source-styles',
	description: 'Sync source styles from MMS to Algolia index',
})
export class SyncStylesFromMMSCommand extends CommandRunner {
	private readonly logger = new Logger(SyncStylesFromMMSCommand.name);
	private readonly BATCH_SIZE = 100;
	private readonly PARALLEL_WORKERS = 5;
	private readonly MMS_TIMEOUT_MS = 50000;

	constructor(
		private readonly processStyleService: ProcessStyleService,
		private readonly mmsService: MmsService,
		private readonly styleAlternativesService: StyleAlternativesService,
	) {
		super();
	}

	@CronJobExecution({
		jobName: 'sync-source-styles',
		context: {
			batchSize: 20,
			parallelWorkers: 5,
			timeoutMs: 50000,
		},
	})
	async run(): Promise<void> {
		const categories = await this.mmsService.fetchCategories();

		const firstBatch = await this.processStyleService.fetchStylesFromMMS({
			page: 1,
			perPage: this.BATCH_SIZE,
			timeoutMs: this.MMS_TIMEOUT_MS,
		});
		const totalStyles = firstBatch.total_entries;
		const totalPages = Math.ceil(totalStyles / this.BATCH_SIZE);

		this.logger.log(`Total styles: ${totalStyles}, Total pages: ${totalPages}`);

		const bar = new ProgressBar({ total: totalStyles });

		let processedStyles = 0;
		let updatedStyles = 0;
		let errorCount = 0;

		const pages = Array.from({ length: totalPages }, (_, i) => i + 1).slice(158, 160);

		await runWithConcurrencyLimit({
			items: pages,
			concurrency: this.PARALLEL_WORKERS,
			handler: async (page) => {
				return this.processPage({ page, categories, bar });
			},
			onItemComplete: (result) => {
				processedStyles += result.processed;
				updatedStyles += result.updated;

				if (processedStyles % (this.BATCH_SIZE * 10) === 0) {
					this.logger.log(
						`Progress: ${processedStyles}/${totalStyles} processed, ${updatedStyles} updated, ${errorCount} errors`,
					);
				}
			},
			onItemError: (error, page) => {
				errorCount++;
				this.logger.error(`Failed to process page ${page}:`, error);
			},
		});

		bar.finish();

		this.logger.log(
			`Sync completed. Processed: ${processedStyles}, Updated: ${updatedStyles}, Errors: ${errorCount}`,
		);
	}

	private async processPage({
		categories,
		bar,
		page,
	}: {
		page: number;
		categories: MMSAllStyleCategory[];
		bar: ProgressBar;
	}): Promise<{ processed: number; updated: number }> {
		const response = await this.processStyleService.fetchStylesFromMMS({
			page,
			perPage: this.BATCH_SIZE,
			timeoutMs: this.MMS_TIMEOUT_MS,
		});

		if (response.styles.length === 0) {
			return { processed: 0, updated: 0 };
		}

		let pageProcessed = 0;
		let pageUpdated = 0;

		for (const style of response.styles) {
			if (String(style.id) !== '1673300') {
				continue;
			}
			const result = await this.processStyle({ style, categories });
			pageProcessed++;

			if (result.updated) {
				pageUpdated++;
			}

			bar.increment({ by: 1, metadata: { updatedCount: pageUpdated } });
		}

		return { processed: pageProcessed, updated: pageUpdated };
	}

	private async processStyle({
		style,
		categories,
	}: {
		style: MMSStyleToProcess;
		categories: MMSAllStyleCategory[];
	}): Promise<{ updated: boolean }> {
		try {
			const wasUpdated = await this.processStyleService.process({
				style,
				allCategories: categories,
			});

			await this.syncStyleAlternatives({ styleId: style.id });

			return { updated: wasUpdated };
		} catch (error) {
			this.logger.error(`Error processing style ${style.id}:`, error);
			return { updated: false };
		}
	}

	private async syncStyleAlternatives({ styleId }: { styleId: number }): Promise<void> {
		try {
			const complementsResponse = await this.mmsService.fetchStyleComplements({
				styleId,
			});

			if (!complementsResponse) {
				return;
			}

			const alternativesComplement = complementsResponse.complements.find(
				(c) => c.name === 'alternatives',
			);

			if (!alternativesComplement || alternativesComplement.style_ids.length === 0) {
				return;
			}

			await this.styleAlternativesService.bulkUpsertStyleAlternatives({
				styleId,
				alternativeStyleIds: alternativesComplement.style_ids,
			});

			this.logger.debug(
				`Synced ${alternativesComplement.style_ids.length} alternatives for style ${styleId}`,
			);
		} catch (error) {
			this.logger.warn(
				`Failed to sync alternatives for style ${styleId}: ${error instanceof Error ? error.message : String(error)}`,
			);
		}
	}
}

